  if(sel.type==="artist"&&artistDetail){const ad=artistDetail;return wrap(<>{hdr(ad.name,"Artist")}<div style={{padding:24,maxWidth:1200,margin:"0 auto",display:"flex",flexDirection:"column",gap:22}}><div style={{display:"flex",gap:14,flexWrap:"wrap"}}><StatCard label="Plays" value={ad.total} color={P[0]}/><StatCard label="Songs" value={ad.songs.length} color={P[4]}/><StatCard label="Leaders" value={ad.leaders.length} color={P[7]}/></div><div style={{display:"flex",gap:22,flexWrap:"wrap"}}><div style={{...cd(),flex:1,minWidth:260}}><h3 style={{margin:"0 0 14px",fontWeight:700,fontSize:17}}>Songs</h3><HBar data={ad.songs.slice(0,10)} labelKey="title" valKey="count" valName="Plays" onItemClick={t2=>go("song",t2)}/></div><div style={{...cd(),flex:1,minWidth:220}}>{ad.keys.length>0&&<><h3 style={{margin:"0 0 14px",fontWeight:700,fontSize:17}}>Keys</h3><ResponsiveContainer width="100%" height={160}><PieChart><Pie data={ad.keys} dataKey="count" nameKey="key" cx="50%" cy="50%" outerRadius={60} innerRadius={25} onClick={d=>{if(d?.key)go("key",d.key)}} style={{cursor:"pointer"}}>{ad.keys.map((e,i)=><Cell key={i} fill={KC[e.key]||P[i%P.length]} style={{cursor:"pointer"}}/>)}</Pie><Tooltip content={<CTT/>}/></PieChart></ResponsiveContainer><KL data={ad.keys} clickable/></>}<h3 style={{margin:"20px 0 10px",fontWeight:700,fontSize:17}}>Leaders</h3>{ad.leaders.map((l,i)=><div key={i} onClick={()=>go("leader",l.name)} style={{display:"flex",alignItems:"center",gap:8,padding:"6px 0",borderBottom:`1px solid ${t.cb}`,cursor:"pointer"}}>{avatar(l.name)}<span style={{fontSize:13,color:t.t2,flex:1,fontWeight:500}}>{l.name}</span><span style={{fontSize:12,color:t.t3,fontWeight:600}}>{l.count}</span></div>)}</div></div></div></>)}
